import{PersonaCardV1Schema as o,PersonaCardV2Schema as n,PersonaCardV3Schema as c}from"./types.js";export function parseCard(r){const e=JSON.parse(r),s=c.safeParse(e);if(s.success)return s.data;const a=n.safeParse(e);if(a.success)return a.data;const t=o.safeParse(e);if(t.success)return upgradeV1toV2(t.data);throw new Error(`Failed to parse character card: V3 error=${s.error.message}; V2 error=${a.error.message}; V1 error=${t.error.message}`)}export function serializeCard(r){return JSON.stringify(r,null,2)}export function upgradeV1toV2(r){return{spec:"chara_card_v2",spec_version:"2.0",data:{name:r.name,description:r.description,personality:r.personality,scenario:r.scenario,first_mes:r.first_mes,mes_example:r.mes_example,creator_notes:"",character_version:"",system_prompt:"",post_history_instructions:"",tags:r.tags,creator:"",alternate_greetings:[],extensions:{}}}}
